<?php
namespace App\Http\Controllers;
use App\Models\ParticipantConsentEvent;use App\Models\ProjectConsentDefinition;use App\Models\ProjektHasPersonen;use Illuminate\Http\Request;use Illuminate\Validation\Rule;use Inertia\Inertia;
class PortalConsentController extends Controller
{
 public function index(Request $request){$participations=ProjektHasPersonen::query()->where('personen_id',$request->user()->person_id)->with('projekt:id,name,portal_feature_settings')->get()->filter(fn($p)=>$p->projekt->portalFeatureEnabled('consents_and_approvals'))->values();$definitions=ProjectConsentDefinition::query()->whereIn('project_id',$participations->pluck('projekt_id'))->where('active',true)->orderBy('sort_order')->orderByDesc('version')->get()->groupBy(fn($d)=>$d->project_id.':'.$d->key)->map->first()->values();$events=ParticipantConsentEvent::query()->whereIn('project_person_id',$participations->pluck('id'))->with('definition:id,title,purpose,content,allow_withdrawal')->orderBy('occurred_at')->get();return Inertia::render('ParticipantPortal/Consents',['participations'=>$participations,'definitions'=>$definitions,'events'=>$events]);}
 public function act(Request $request,ProjectConsentDefinition $definition){$data=$request->validate(['project_person_id'=>['required','integer'],'action'=>['required',Rule::in(['accepted','withdrawn'])],'confirmed'=>['required','accepted']]);$participation=ProjektHasPersonen::query()->whereKey($data['project_person_id'])->where('personen_id',$request->user()->person_id)->with('projekt')->firstOrFail();abort_unless((int)$definition->project_id===(int)$participation->projekt_id&&$definition->active&&$participation->projekt->portalFeatureEnabled('consents_and_approvals'),404);$latest=ParticipantConsentEvent::query()->where('project_person_id',$participation->id)->where('definition_key',$definition->key)->latest('occurred_at')->latest('id')->first();if($data['action']==='withdrawn'){abort_unless($definition->allow_withdrawal,422,'Diese Einwilligung kann nicht im Portal widerrufen werden.');abort_unless($latest?->action==='accepted',422,'Es liegt keine aktive Einwilligung vor.');}else{abort_if($latest?->action==='accepted'&&(int)$latest->definition_version===(int)$definition->version,422,'Diese Version wurde bereits angenommen.');}$event=ParticipantConsentEvent::query()->create(['project_person_id'=>$participation->id,'consent_definition_id'=>$definition->id,'actor_user_id'=>$request->user()->id,'action'=>$data['action'],'definition_key'=>$definition->key,'definition_version'=>$definition->version,'title_snapshot'=>$definition->title,'content_sha256'=>hash('sha256',$definition->content),'occurred_at'=>now(),'ip_address'=>$request->ip(),'user_agent'=>mb_substr((string)$request->userAgent(),0,500)]);return response()->json(['message'=>$data['action']==='accepted'?'Einwilligung wurde dokumentiert.':'Widerruf wurde dokumentiert.','event'=>$event],201);}
}
